import React, { useState } from 'react';

const BASE_URL = 'http://localhost:4000'; // ili tvoj deployed backend URL

export default function HomePage() {
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');

  const handleSubscribe = async () => {
    if (!email) {
      setMessage('Please enter your email.');
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/subscribe`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });

      if (res.ok) {
        setMessage('Successfully subscribed! 💌');
        setEmail('');
      } else {
        setMessage('Error while subscribing. Try again.');
      }
    } catch (err) {
      console.error('Subscription error:', err);
      setMessage('Server error. Try again later.');
    }
  };

  return (
    <div className="homepage">
      <section className="intro-section">
        <h1 className="main-title">Welcome to Sofia's Bali Blog 🌺</h1>
        <p className="subtitle">
          Join me on this journey as I explore the beauty of Bali, one post at a time. From jungle adventures to seaside cafés, this is where I share everything 🌴✨
        </p>
      </section>

      <section className="newsletter-section">
        <h2>Sign up to our weekly newsletter 💌</h2>
        <div className="newsletter-input">
          <input
            type="email"
            placeholder="Enter your email..."
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <button onClick={handleSubscribe}>Subscribe</button>
        </div>
        {message && <p className="message">{message}</p>}
      </section>
    </div>
  );
}
